const { Sequelize, DataTypes } = require('sequelize');
const sequelize = new Sequelize({ dialect: 'sqlite', storage: './database.sqlite', logging: false });

async function check() {
  // Check SequelizeMeta table
  const [results] = await sequelize.query('SELECT name FROM sqlite_master WHERE type=\"table\"');
  console.log('Tables:', results.map(r => r.name));

  // Check Users schema
  const [cols] = await sequelize.query('PRAGMA table_info(Users)');
  console.log('Users columns:', cols.map(c => c.name + ' (' + c.type + ')'));

  await sequelize.close();
}
check();
"

